from flask import Flask, jsonify
from pymemcache.client.base import Client
import time
import hashlib
import json

app = Flask(__name__)

# Connect to Memcached
memcache_client = Client(('localhost', 11211))

# Mock database function
def mock_database_query(query):
    # Simulate database delay
    time.sleep(0.1)
    return {"result": f"Data for query: {query}", "timestamp": time.time()}

# Generate cache key
def generate_cache_key(query):
    return f"cache_{hashlib.md5(query.encode()).hexdigest()}"

# Cache decorator
def cache_result(ttl=300):
    def decorator(func):
        def wrapper(*args, **kwargs):
            # Generate cache key
            cache_key = generate_cache_key(f"{func.__name__}_{str(args)}_{str(kwargs)}")
            
            # Try to get from cache
            cached_result = memcache_client.get(cache_key)
            if cached_result:
                return json.loads(cached_result)
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            memcache_client.set(cache_key, json.dumps(result), expire=ttl)
            return result
        return wrapper
    return decorator

# API endpoint with caching
@app.route('/api/data/<query>')
@cache_result(ttl=60)
def get_data(query):
    data = mock_database_query(query)
    return jsonify(data)

# Manual cache set/get example
@app.route('/api/cache/set/<key>/<value>')
def cache_set(key, value):
    memcache_client.set(key, value, expire=300)
    return jsonify({"status": "cached"})

@app.route('/api/cache/get/<key>')
def cache_get(key):
    value = memcache_client.get(key)
    if value:
        return jsonify({"key": key, "value": value.decode()})
    return jsonify({"error": "Key not found"})

# Cache clear endpoint
@app.route('/api/cache/clear')
def clear_cache():
    memcache_client.flush_all()
    return jsonify({"status": "cache cleared"})

if __name__ == '__main__':
    app.run(debug=False)